_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: row;   \n  gap: 15px;                \n  margin-bottom: 10px;\n  \n}\n\n.bp-add-section[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;   \n  gap: 15px;                \n  margin-bottom: 20px;\n}\n\n.bp-add-section[_ngcontent-%COMP%]   input[_ngcontent-%COMP%] {\n  padding: 8px;\n  border-radius: 8px;\n  border: 1px solid #ddd;\n}\n\n.add-bp-btn[_ngcontent-%COMP%] {\n  background: #4caf50;\n  border: none;\n  padding: 8px 14px;\n  border-radius: 8px;\n  cursor: pointer;\n  font-weight: 600;\n}\n\n.add-bp-btn[_ngcontent-%COMP%]:hover {\n  background: #43a047;\n}\n\n.prescription-row[_ngcontent-%COMP%] {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  padding: 10px 0;\n  border-bottom: 1px solid #eee;\n}\n\n.analyze-btn[_ngcontent-%COMP%] {\n  padding: 6px 12px;\n  background: #c7a674;\n  color: white;\n  border: none;\n  border-radius: 6px;\n  cursor: pointer;\n}\n\n.analyze-btn[_ngcontent-%COMP%]:hover {\n  background: #b39465;\n}\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
